// Source row = Supabase DB-Webhook payload (inscripciones INSERT) OR direct form post.
const rec = $json.body && $json.body.record ? $json.body.record : ($json.record || $json.body || $json);
const ed = $('Leer Edicion Activa').first().json;
const flat = Object.assign({}, rec);

// Edicion activa UUID (scalar) from getAll result
flat.edicionActiva = ed.id || '';

// Review deadline from plazos_revision (JSONB -> already object/array, or string)
const now = new Date();
let rondas = [];
const plazosRaw = ed.plazos_revision || ed['Plazos Revision'] || [];
try { rondas = Array.isArray(plazosRaw) ? plazosRaw : JSON.parse(plazosRaw); } catch (e) { rondas = []; }
flat.plazoRevision = 'Fuera de plazo';
flat.fechaPlazo = '';
for (const r of rondas) {
  if (now <= new Date(r.fecha + 'T23:59:59')) { flat.plazoRevision = r.label; flat.fechaPlazo = r.fecha + 'T23:59:59.000Z'; break; }
}

// Map form modules -> Modulo Solicitado
const modulesKey = Object.keys(flat).find(k => k.toLowerCase().includes('which modules'));
const formModules = modulesKey ? flat[modulesKey] : [];
const joined = Array.isArray(formModules) ? formModules.join(' ').toLowerCase() : String(formModules).toLowerCase();
if (joined.includes('1 + 2 + 3') || joined.includes('1, 2 and 3') || joined.includes('total')) flat.moduloSolicitado = 'Formacion Completa (Modulos 1 + 2 + 3)';
else if (joined.includes('2 + 3') || joined.includes('2 and 3')) flat.moduloSolicitado = 'Pack Modulos 2 + 3';
else if (joined.includes('1 + 2') || joined.includes('1 and 2')) flat.moduloSolicitado = 'Pack Modulos 1 + 2';
else if (joined.includes('module 3') || joined.includes('modulo 3')) flat.moduloSolicitado = 'Modulo 3';
else if (joined.includes('module 2') || joined.includes('modulo 2')) flat.moduloSolicitado = 'Modulo 2';
else flat.moduloSolicitado = 'Modulo 1';

// Country -> Idioma (Supabase enum: 'Espanol'/'Ingles', NO tilde)
const country = (flat['What country are you come from?'] || '').toLowerCase();
const spanishCountries = ['spain','espa','mexico','colombia','argentina','peru','chile','venezuela','ecuador','guatemala','cuba','bolivia','dominican','honduras','paraguay','el salvador','nicaragua','costa rica','panama','uruguay'];
flat.idiomaSb = spanishCountries.some(c => country.includes(c)) ? 'Espanol' : 'Ingles';

// Normalize scalar email/nombre (already scalar in Supabase row; guard anyway)
flat.Email = Array.isArray(flat.email) ? flat.email[0] : (flat.email || flat.Email || '');
flat.Nombre = Array.isArray(flat.nombre) ? flat.nombre[0] : (flat.nombre || flat.Nombre || '');
flat.emailPareja = (flat['Email Pareja'] || flat.email_pareja || '').toString();

return [{ json: flat }];

const original = $('Combinar Datos').first().json;
const records = $input.all().map(i => i.json).filter(r => r && (r.id || r.email));
if (records.length > 0) {
  return [{ json: { skip: true, reason: 'Alumno ya existe con email: ' + (original.Email||'').toLowerCase() } }];
}
return [{ json: original }];

const original = $('Verificar Duplicado').first().json;
if (original.skip) return [{ json: { skip: true } }];
const created = $('Crear Alumno').first().json;
const alumnoId = created.id || '';            // server-generated UUID, NOT recId
const email = original.Email || '';
const nombre = original.Nombre || 'Alumno/a';
if (!email) return [{ json: { skip: true } }];
const idioma = (created.idioma || original.idiomaSb || '').toString().toLowerCase();
const tallyForm2 = 'https://tally.so/r/vGMKM0?fullname=' + encodeURIComponent(nombre) + '&email=' + encodeURIComponent(email) + '&alumnoId=' + encodeURIComponent(alumnoId);
return [{ json: { email, nombre, alumnoId, idioma, subject: 'Confirmacion de inscripcion - ProEv', tallyForm2 } }];

const prev = $('Tiene Email?').item.json;
const inboxId = $input.first().json.id || '';
const alumnoId = prev.alumnoId;
const email = prev.email;
const nombre = prev.nombre;
const idioma = prev.idioma;
const subject = prev.subject;
const tallyForm2 = prev.tallyForm2;
const trackPixel = 'https://hooks.dravaautomations.com/webhook/sb-email-track?alumno=' + alumnoId + '&tipo=inscripcion&inboxId=' + inboxId;
const trackedFormUrl = 'https://hooks.dravaautomations.com/webhook/sb-email-click?alumno=' + alumnoId + '&tipo=inscripcion&inboxId=' + inboxId + '&url=' + encodeURIComponent(tallyForm2);
const displayName = nombre || 'Alumno/a';
const logo = 'https://sawa-dev-2-storage-bucket.storage.googleapis.com/profiles/nx0mtgi3zeb8acxp-d7a42.png';
const inner = '<div style="text-align:center;margin-bottom:30px"><div style="font-size:36px">&#128131;</div><h1 style="color:#0C5A45;font-size:24px;margin:10px 0">&iexcl;Hola ' + displayName + '!</h1></div>'
  + '<p style="color:#333;line-height:1.7;font-size:16px">&iexcl;Gracias por inscribirte en nuestro curso de formaci&oacute;n para profesores de bachata!</p>'
  + '<p style="color:#333;line-height:1.7;font-size:16px">Hemos recibido tu solicitud correctamente. Como parte del proceso de selecci&oacute;n, necesitamos que nos env&iacute;es un <strong>video de presentaci&oacute;n</strong> para que podamos evaluar tu nivel.</p>'
  + '<div style="text-align:center;margin:30px 0"><a href="' + trackedFormUrl + '" style="display:inline-block;background-color:#0C5A45;color:#ffffff;padding:14px 36px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px">ENVIAR MI VIDEO</a></div>'
  + '<div style="background:#f0f7f4;border-radius:8px;padding:20px;margin:25px 0"><p style="color:#0C5A45;font-weight:600;margin:0 0 8px">&iquest;C&oacute;mo funciona el proceso?</p><ol style="color:#333;line-height:1.8;margin:0;padding-left:20px"><li>Env&iacute;a tu video a trav&eacute;s del enlace de arriba</li><li>Nuestro equipo revisar&aacute; tu video y te notificaremos el resultado</li><li>Si es aprobado, te enviaremos el enlace de pago</li></ol></div>'
  + '<p style="color:#333;line-height:1.7;font-size:16px">Si tienes alguna pregunta, no dudes en responder a este email.</p>';
const sig = '<p style="margin:25px 0 0;text-align:center;font-size:15px;color:#1A1A1A;"><strong>Alonso &amp; Noelia</strong></p>';
const social = '<p style="margin-bottom:15px;"><a href="https://www.instagram.com/alonsoynoelia" style="color:#1A1A1A;text-decoration:none;font-size:11px;font-weight:600;letter-spacing:1px;margin:0 8px;">INSTAGRAM</a> <a href="https://www.youtube.com/@alonsoynoelia" style="color:#1A1A1A;text-decoration:none;font-size:11px;font-weight:600;letter-spacing:1px;margin:0 8px;">YOUTUBE</a> <a href="https://alonsoynoeliaonline.com" style="color:#1A1A1A;text-decoration:none;font-size:11px;font-weight:600;letter-spacing:1px;margin:0 8px;">WEB</a></p><p style="font-size:10px;color:#A9A9A9;margin:0;">&copy; 2026 Alonso &amp; Noelia.</p>';
const htmlBody = '<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head><body style="margin:0;padding:0"><center><table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color:#F6F3EE;"><tr><td align="center" valign="top" style="padding:20px;"><table width="500" border="0" cellpadding="0" cellspacing="0" style="width:500px;max-width:500px;margin:0 auto;font-family:Inter,Helvetica Neue,Arial,sans-serif;"><tr><td align="center" style="padding-bottom:25px;"><img src="' + logo + '" alt="Alonso y Noelia" width="160" style="display:block;"></td></tr><tr><td style="background-color:#fff;border-radius:4px;overflow:hidden;box-shadow:0 5px 15px rgba(0,0,0,0.03);"><table width="100%" border="0" cellpadding="0" cellspacing="0"><tr><td style="padding:40px 30px;font-size:16px;line-height:1.7;color:#333;">' + inner + sig + '</td></tr></table></td></tr><tr><td style="padding:25px 0;text-align:center;">' + social + '</td></tr></table></td></tr></table></center><img src="' + trackPixel + '" width="1" height="1" style="display:none" alt="" /></body></html>';
return [{ json: { email, nombre: displayName, alumnoId, inboxId, idioma, subject, htmlBody, tallyForm2, trackPixel } }];

const llmOutput = $json.output || {};
const original = $('Traducir?').item.json;
return [{ json: { email: original.email, nombre: original.nombre, alumnoId: original.alumnoId, inboxId: original.inboxId, subject: llmOutput.subject || original.subject, htmlBody: llmOutput.htmlBody || original.htmlBody, trackPixel: original.trackPixel, idioma: original.idioma } }];

const formData = $('Combinar Datos').first().json;
const created = $('Crear Alumno').first().json;
if (formData.skip || !created.id) return [{ json: { skip: true } }];
const emailPareja = (formData.emailPareja || '').toString().trim().toLowerCase();
const alumnoId = created.id;                       // UUID scalar
const alumnoEmail = (formData.Email || '').toString().trim().toLowerCase();
return [{ json: { emailPareja, alumnoId, alumnoEmail, skip: !emailPareja } }];

const initData = $('Pareja - Init').first().json;
const records = $input.all().map(i => i.json).filter(r => r && r.id);
const alumnoAId = initData.alumnoId;
const alumnoAEmail = initData.alumnoEmail;
const emailPareja = initData.emailPareja;
if (records.length === 0) {
  return [{ json: { alumnoAId, parejaEmailA: emailPareja, parejaLinkA: null, alumnoBId: null, shouldPatchB: false } }];
}
const partner = records[0];
const alumnoBId = partner.id;                        // UUID scalar
const bLink = partner.pareja_alumno_id || null;
const alreadyLinked = bLink === alumnoAId;
return [{ json: { alumnoAId, parejaEmailA: emailPareja, parejaLinkA: alumnoBId, alumnoBId, parejaEmailB: alumnoAEmail, parejaLinkB: alumnoAId, shouldPatchB: !alreadyLinked } }];
